#!/usr/bin/env bun
// PAI Obsidian Capture Server
// Unified capture webhook replacing ObsidianVoiceWebhook.ts
// Endpoints: POST /voice-note (iOS compat), POST /capture (text), POST /youtube, GET / (web UI)
// Port: 27337 — same as predecessor, drop-in replacement

import { join } from 'path'
import { mkdir, unlink } from 'fs/promises'
import { existsSync } from 'fs'
import { spawn } from 'child_process'

const PORT = parseInt(process.env.VOICE_WEBHOOK_PORT || '27337')
const VAULT = '/opt/docker/appdata/obsidian-jellybase/vault/OB_v2'
const INBOX = join(VAULT, '00 INBOX')
const SECRET = process.env.VOICE_WEBHOOK_SECRET || ''
const YTDLP = process.env.YTDLP_PATH || '/home/jellypai/.local/bin/yt-dlp'
const YOUTUBE_TIMEOUT_MS = 30_000

function isoDate(): string {
  return new Date().toISOString().slice(0, 10)
}

function timestamp(): string {
  return new Date().toISOString().replace('T', ' ').slice(0, 16)
}

function slugDate(): string {
  return new Date().toISOString().slice(0, 19).replace(/[T:]/g, '-')
}

function isYouTubeUrl(url: string): boolean {
  try {
    const u = new URL(url)
    return u.hostname === 'youtube.com' || u.hostname === 'www.youtube.com' ||
      u.hostname === 'youtu.be' || u.hostname === 'm.youtube.com'
  } catch {
    return false
  }
}

function parseVtt(content: string): string {
  const lines = content.split('\n')
  const text: string[] = []
  let prev = ''
  for (const line of lines) {
    const trimmed = line.trim()
    if (!trimmed) continue
    if (trimmed === 'WEBVTT') continue
    // Skip timestamp lines: 00:00:00.000 --> 00:00:05.000
    if (/^\d{2}:\d{2}[\d:.]+\s*-->\s*\d{2}:\d{2}/.test(trimmed)) continue
    // Skip metadata lines like Kind: captions, Language: en
    if (/^(Kind|Language|NOTE|STYLE)[\s:]/.test(trimmed)) continue
    // Strip HTML tags
    const clean = trimmed.replace(/<[^>]+>/g, '').trim()
    if (!clean || clean === prev) continue
    text.push(clean)
    prev = clean
  }
  return text.join(' ').trim().slice(0, 4000)
}

function runProcess(cmd: string, args: string[], timeoutMs: number): Promise<{ stdout: string; stderr: string; code: number }> {
  return new Promise((resolve) => {
    let stdout = ''
    let stderr = ''
    const proc = spawn(cmd, args, { env: { ...process.env, PATH: `/home/jellypai/.local/bin:${process.env.PATH}` } })
    proc.stdout?.on('data', (d: Buffer) => { stdout += d.toString() })
    proc.stderr?.on('data', (d: Buffer) => { stderr += d.toString() })
    const timer = setTimeout(() => { proc.kill(); resolve({ stdout, stderr, code: -1 }) }, timeoutMs)
    proc.on('close', (code: number | null) => { clearTimeout(timer); resolve({ stdout, stderr, code: code ?? 0 }) })
  })
}

async function extractYouTube(url: string): Promise<{ title: string; transcript: string; ok: boolean }> {
  // Step 1: get title
  const titleResult = await runProcess(YTDLP, ['--print', '%(title)s', '--no-download', url], YOUTUBE_TIMEOUT_MS)
  const title = titleResult.stdout.trim() || 'YouTube Video'

  // Step 2: extract subtitles
  const tmpId = `yt-${Date.now()}`
  const tmpBase = `/tmp/${tmpId}`
  const subResult = await runProcess(
    YTDLP,
    ['--write-auto-sub', '--skip-download', '--sub-format', 'vtt',
      '--sub-lang', 'en', '--output', `${tmpBase}.%(ext)s`, url],
    YOUTUBE_TIMEOUT_MS
  )

  if (subResult.code !== 0) {
    return { title, transcript: '', ok: false }
  }

  // Find the VTT file
  const vttCandidates = [
    `${tmpBase}.en.vtt`,
    `${tmpBase}.en-orig.vtt`,
  ]
  for (const candidate of vttCandidates) {
    if (existsSync(candidate)) {
      const raw = await Bun.file(candidate).text()
      unlink(candidate).catch(() => {})
      return { title, transcript: parseVtt(raw), ok: true }
    }
  }

  // VTT not found — try any .vtt in /tmp matching our id
  return { title, transcript: '', ok: false }
}

function buildVoiceNote(transcription: string, title?: string): string {
  const ts = timestamp()
  const noteTitle = title || `Voice ${ts}`
  return `---
title: "${noteTitle}"
type: capture
date: ${isoDate()}
tags: [inbox, voice]
source: voice
---

${transcription.trim()}
`
}

function buildCaptureNote(text: string, title?: string, source = 'text'): string {
  const ts = timestamp()
  const noteTitle = title || `Capture ${ts}`
  return `---
title: "${noteTitle}"
type: capture
date: ${isoDate()}
tags: [inbox]
source: ${source}
---

${text.trim()}
`
}

function buildYouTubeNote(url: string, videoTitle: string, transcript: string, noteTitle?: string): string {
  const ts = timestamp()
  const title = noteTitle || `YouTube — ${videoTitle}`
  const body = transcript
    ? `# ${videoTitle}\n\n${url}\n\n## Transcript\n\n${transcript}`
    : `# ${videoTitle}\n\n${url}\n\n*Transcript unavailable — subtitles could not be extracted.*`
  return `---
title: "${title}"
type: capture
date: ${isoDate()}
tags: [inbox, youtube]
source: youtube
url: "${url}"
---

${body}
`
}

function checkAuth(req: Request): boolean {
  if (!SECRET) return true
  return req.headers.get('x-pai-secret') === SECRET
}

function logReq(method: string, path: string, status: number, file?: string): void {
  const msg = `[${timestamp()}] ${method} ${path} → ${status}${file ? ` (${file})` : ''}`
  console.log(msg)
}

const WEB_UI = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>PAI Capture</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
           background: #1a1a2e; color: #e0e0e0; min-height: 100vh;
           display: flex; align-items: center; justify-content: center; padding: 1rem; }
    .card { background: #16213e; border-radius: 12px; padding: 1.5rem;
            width: 100%; max-width: 520px; box-shadow: 0 4px 24px rgba(0,0,0,0.4); }
    h1 { font-size: 1.25rem; margin-bottom: 1.25rem; color: #7c9cbf; }
