#!/usr/bin/env bun
// MigrateVaultFrontmatter.ts — normalise Obsidian vault notes to unified schema
// Usage:
//   bun MigrateVaultFrontmatter.ts --dry-run
//   bun MigrateVaultFrontmatter.ts --dry-run --folder "02 Cards"
//   bun MigrateVaultFrontmatter.ts --folder "02 Cards" --type meeting

import { readdir, stat, rename } from 'fs/promises'
import { join, relative } from 'path'

const VAULT = '/opt/docker/appdata/obsidian-jellybase/vault/OB_v2'
const LOG_PATH = '/home/jellypai/.claude/PAI/MEMORY/WORK/20260607-140000_obsidian-capture-system/migration.log'

const ACTIVE_FOLDERS = ['00 INBOX', '02 Cards', '03 Spaces', '05 Journal', '07 PAI']

const EXCLUDED_PATHS = ['Archive/', '.obsidian/', '.trash/', '_ephemeral/', '06 Toolkit/Templates/_']

// Parse CLI args
const args = process.argv.slice(2)
const DRY_RUN = args.includes('--dry-run')
const folderIdx = args.indexOf('--folder')
const typeIdx = args.indexOf('--type')
const FOLDER_FILTER = folderIdx !== -1 ? args[folderIdx + 1] : null
const TYPE_FILTER = typeIdx !== -1 ? args[typeIdx + 1] : null

const counters = { modified: 0, skipped: 0, unchanged: 0, errors: 0 }
const logLines: string[] = []

function log(msg: string) {
  const line = `[${new Date().toISOString()}] ${msg}`
  logLines.push(line)
  console.log(msg)
}

function extractFrontmatter(content: string): { fm: Record<string, string>; body: string } | null {
  if (!content.startsWith('---')) return null
  const end = content.indexOf('\n---', 3)
  if (end === -1) return null
  const fmRaw = content.slice(3, end).trim()
  const body = content.slice(end + 4)
  const fm: Record<string, string> = {}

  // Parse simple key: value pairs (handles quoted values, arrays, and multi-word values)
  const lines = fmRaw.split('\n')
  let currentKey = ''
  const arrayLines: string[] = []
  let inArray = false

  for (const line of lines) {
    // Detect array continuation lines
    if (inArray && (line.startsWith('  - ') || line.startsWith('- '))) {
      arrayLines.push(line.trim().replace(/^-\s*/, '').replace(/^["']|["']$/g, ''))
      continue
    }
    if (inArray) {
      // Inline array or end of array — store accumulated
      fm[currentKey] = `[${arrayLines.join(', ')}]`
      inArray = false
      arrayLines.length = 0
    }

    const match = line.match(/^([A-Za-z_-][A-Za-z0-9_-]*):\s*(.*)$/)
    if (!match) continue
    const [, key, val] = match
    currentKey = key.toLowerCase()

    if (val.trim() === '' || val.trim() === '[]') {
      // Check next lines for array items
      fm[currentKey] = val.trim() || ''
      inArray = val.trim() === ''
      continue
    }
    if (val.trim().startsWith('[') && val.trim().endsWith(']')) {
      fm[currentKey] = val.trim()
      continue
    }
    // Strip quotes from value
    fm[currentKey] = val.trim().replace(/^["']|["']$/g, '')
  }
  if (inArray && arrayLines.length > 0) {
    fm[currentKey] = `[${arrayLines.join(', ')}]`
  }

  return { fm, body }
}

function normaliseDate(raw: string): string {
  if (!raw) return ''
  const s = raw.trim().replace(/^["']|["']$/g, '')
  // Already YYYY-MM-DD
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s
  // YYYY-MM-DD HH:MM or YYYY-MM-DD HH:MM:SS
  const dtMatch = s.match(/^(\d{4}-\d{2}-\d{2})[T \d:]+/)
  if (dtMatch) return dtMatch[1]
  // [[YYYY-MM-DD]]
  const wikiMatch = s.match(/\[\[(\d{4}-\d{2}-\d{2})/)
  if (wikiMatch) return wikiMatch[1]
  // Try Date.parse
  const parsed = Date.parse(s)
  if (!isNaN(parsed)) return new Date(parsed).toISOString().slice(0, 10)
  return s
}

function normaliseTags(raw: string): string {
  if (!raw) return '[]'
  // Already a clean array: [tag1, tag2]
  const inside = raw.trim().match(/^\[(.+)\]$/)
  const items = inside ? inside[1] : raw
  const tags = items.split(',').map(t =>
    t.trim()
      .replace(/^["'#\s]+|["'\s]+$/g, '')  // strip quotes and leading #
      .replace(/^My\//, '')                  // strip My/ prefix from journal tags if desired? No — keep hierarchy
  ).filter(Boolean)
  return tags.length ? `[${tags.join(', ')}]` : '[]'
}

function rebuildFrontmatter(fm: Record<string, string>, noteTitle: string, fileMtime: string): { changed: boolean; result: Record<string, string>; changes: string[] } {
  const out = { ...fm }
  const changes: string[] = []

  // 1. Date normalisation
  const dateCreated = fm['date-created'] || fm['date_created']
  const dateAdded = fm['date-added'] || fm['date_added']
  const existingDate = fm['date']

  if (dateCreated) {
    const normalised = normaliseDate(dateCreated)
    if (!existingDate || existingDate !== normalised) {
      changes.push(`date: ${existingDate || '(missing)'} → ${normalised}`)
      out['date'] = normalised
    }
    delete out['date-created']
    delete out['date_created']
  } else if (dateAdded) {
    const normalised = normaliseDate(dateAdded)
    if (!existingDate || existingDate !== normalised) {
      changes.push(`date: ${existingDate || '(missing)'} → ${normalised}`)
      out['date'] = normalised
    }
    delete out['date-added']
    delete out['date_added']
  } else if (existingDate) {
    const normalised = normaliseDate(existingDate)
    if (normalised !== existingDate) {
      changes.push(`date: ${existingDate} → ${normalised}`)
      out['date'] = normalised
    }
  } else {
    changes.push(`date: (missing) → ${fileMtime}`)
    out['date'] = fileMtime
  }

  // 2. Tag normalisation
  if (fm['tags']) {
    const normalised = normaliseTags(fm['tags'])
    if (normalised !== fm['tags']) {
      changes.push(`tags: ${fm['tags']} → ${normalised}`)
      out['tags'] = normalised
    }
  } else {
    out['tags'] = '[]'
    changes.push('tags: (missing) → []')
  }

  // 3. Type field (handle capital T — normalise key to lowercase)
  const type = out['type'] || ''
  if (!type) {
    out['type'] = 'note'
    changes.push('type: (missing) → note')
  } else if (type === 'voice') {
    out['type'] = 'capture'
    out['source'] = 'voice'
    changes.push('type: voice → capture')
    changes.push('source: (added) voice')
  }
  // Remove capital-T duplicate if it appeared
  if (fm['type-original-capitalized']) delete out['type-original-capitalized']

  // 4. Title field
  if (!out['title'] || out['title'] === '') {
    const derivedTitle = noteTitle.replace(/^\d{4}-\d{2}-\d{2}\s+/, '').replace(/\.md$/i, '')
    out['title'] = derivedTitle
    changes.push(`title: (missing) → ${derivedTitle}`)
  }

  // 5. Source field — add empty if missing for capture/note
  if (!out['source'] && (out['type'] === 'capture' || out['type'] === 'note')) {
    out['source'] = ''
    changes.push('source: (added empty)')
  }

  const changed = changes.length > 0
  return { changed, result: out, changes }
}

function serialiseFrontmatter(fm: Record<string, string>): string {
  // Preferred field order for the unified schema
  const order = ['title', 'type', 'date', 'tags', 'source', 'status', 'topic', 'url',
    'attendees', 'company', 'summary']
  const lines: string[] = []
  const written = new Set<string>()

  for (const key of order) {
    if (key in fm) {
      lines.push(`${key}: ${fm[key]}`)
      written.add(key)
    }
  }
  // Any remaining keys not in the order list
  for (const [k, v] of Object.entries(fm)) {
    if (!written.has(k)) {
      lines.push(`${k}: ${v}`)
    }
  }
  return lines.join('\n')
}

async function processFile(filePath: string): Promise<void> {
  const relPath = relative(VAULT, filePath)

  // Exclusion checks
  for (const excl of EXCLUDED_PATHS) {
    if (relPath.includes(excl) || filePath.includes(excl)) {
      log(`[EXCLUDED] ${relPath}`)
      counters.skipped++
      return
    }
  }

  let content: string
  try {
    content = await Bun.file(filePath).text()
  } catch (e) {
    log(`[ERROR] ${relPath}: could not read — ${e}`)
    counters.errors++
    return
  }

  const parsed = extractFrontmatter(content)
  if (!parsed) {
    // No frontmatter — create minimal one
    const title = filePath.split('/').pop()?.replace('.md', '') || 'Untitled'
    const fileStat = await stat(filePath).catch(() => null)
    const mtime = fileStat ? new Date(fileStat.mtimeMs).toISOString().slice(0, 10) : new Date().toISOString().slice(0, 10)
    const minimalFm = `title: ${title}\ntype: note\ndate: ${mtime}\ntags: []\nsource: `
    const newContent = `---\n${minimalFm}\n---\n${content}`
    log(`[MODIFIED] ${relPath} — added minimal frontmatter`)
    counters.modified++
    if (!DRY_RUN) await Bun.write(filePath, newContent)
    return
  }

  const { fm, body } = parsed

  // Skip pai-session notes
  if (fm['type'] === 'pai-session') {
    log(`[SKIPPED] ${relPath} — type: pai-session`)
    counters.skipped++
    return
  }

  // Type filter
  if (TYPE_FILTER && fm['type'] !== TYPE_FILTER) {
    counters.skipped++
    return
  }

  const filename = filePath.split('/').pop() || 'Untitled.md'
  const fileStat = await stat(filePath).catch(() => null)
  const mtime = fileStat ? new Date(fileStat.mtimeMs).toISOString().slice(0, 10) : new Date().toISOString().slice(0, 10)

  const { changed, result, changes } = rebuildFrontmatter(fm, filename, mtime)

  if (!changed) {
    counters.unchanged++
    return
  }

  const newFm = serialiseFrontmatter(result)
  const newContent = `---\n${newFm}\n---${body}`

  log(`[MODIFIED] ${relPath}`)
  for (const c of changes) log(`  ${c}`)
  counters.modified++

  if (!DRY_RUN) {
    try {
      await Bun.write(filePath, newContent)
    } catch (e) {
      log(`[ERROR] ${relPath}: could not write — ${e}`)
      counters.errors++
      counters.modified--
    }
  }
}

async function walkDir(dir: string): Promise<void> {
  let entries: string[]
  try {
    entries = await readdir(dir)
  } catch {
    return
  }
  for (const entry of entries) {
    const full = join(dir, entry)
    let s
    try { s = await stat(full) } catch { continue }
    if (s.isDirectory()) {
      await walkDir(full)
    } else if (entry.endsWith('.md')) {
      await processFile(full)
    }
  }
}

async function main() {
  const mode = DRY_RUN ? 'DRY RUN' : 'LIVE'
  log(`=== MigrateVaultFrontmatter — ${mode} ===`)
  if (FOLDER_FILTER) log(`Folder filter: ${FOLDER_FILTER}`)
  if (TYPE_FILTER) log(`Type filter: ${TYPE_FILTER}`)

  const folders = FOLDER_FILTER ? [FOLDER_FILTER] : ACTIVE_FOLDERS

  for (const folder of folders) {
    const dir = join(VAULT, folder)
    log(`--- Processing: ${folder} ---`)
    await walkDir(dir)
  }

  const summary = `\n=== SUMMARY (${mode}) ===\nModified: ${counters.modified}\nSkipped:  ${counters.skipped}\nUnchanged: ${counters.unchanged}\nErrors:    ${counters.errors}\n`
  log(summary)

  // Write log
  try {
    await Bun.write(LOG_PATH, logLines.join('\n') + '\n', { createPath: true } as unknown as Parameters<typeof Bun.write>[1])
  } catch {
    // Log write failure is non-fatal
    await Bun.write(LOG_PATH, logLines.join('\n') + '\n').catch(() => {})
  }
}

