#!/usr/bin/env bun
// MigrateVaultFrontmatter.ts — normalise Obsidian vault notes to unified schema
// Usage:
//   bun MigrateVaultFrontmatter.ts --dry-run
//   bun MigrateVaultFrontmatter.ts --dry-run --folder "02 Cards"
//   bun MigrateVaultFrontmatter.ts --folder "02 Cards" --type meeting

import { readdir, stat } from 'fs/promises'
import { join, relative } from 'path'

const VAULT = '/opt/docker/appdata/obsidian-jellybase/vault/OB_v2'
const LOG_PATH = '/home/jellypai/.claude/PAI/MEMORY/WORK/20260607-140000_obsidian-capture-system/migration.log'

const ACTIVE_FOLDERS = ['00 INBOX', '02 Cards', '03 Spaces', '05 Journal', '07 PAI']

const EXCLUDED_SEGMENTS = ['Archive', '.obsidian', '.trash', '_ephemeral']

const args = process.argv.slice(2)
const DRY_RUN = args.includes('--dry-run')
const folderIdx = args.indexOf('--folder')
const typeIdx = args.indexOf('--type')
const FOLDER_FILTER: string | null = folderIdx !== -1 ? args[folderIdx + 1] : null
const TYPE_FILTER: string | null = typeIdx !== -1 ? args[typeIdx + 1] : null

const counters = { modified: 0, skipped: 0, unchanged: 0, errors: 0 }
const logLines: string[] = []

function log(msg: string) {
  const line = `[${new Date().toISOString()}] ${msg}`
  logLines.push(line)
  console.log(msg)
}

function isExcluded(absPath: string): boolean {
  const parts = absPath.replace(VAULT + '/', '').split('/')
  return parts.some(p => EXCLUDED_SEGMENTS.includes(p))
}

// Extract YAML frontmatter — returns null if none
function extractFrontmatter(content: string): { fields: string[][]; body: string } | null {
  if (!content.startsWith('---')) return null
  const second = content.indexOf('\n---', 3)
  if (second === -1) return null
  const fmBlock = content.slice(3, second).trimEnd()
  const body = content.slice(second + 4)

  const fields: string[][] = []
  let pendingKey = ''
  let arrayItems: string[] = []

  for (const line of fmBlock.split('\n')) {
    // Array item continuation
    if (pendingKey && (line.match(/^\s{2}-\s/) || line.match(/^-\s/))) {
      arrayItems.push(line.trim().replace(/^-\s*/, '').replace(/^["']|["']$/g, ''))
      continue
    }
    // Flush pending array
    if (pendingKey && arrayItems.length > 0) {
      fields.push([pendingKey, `[${arrayItems.join(', ')}]`])
      pendingKey = ''
      arrayItems = []
    }

    const m = line.match(/^([A-Za-z_-][A-Za-z0-9_-]*):\s*(.*)$/)
    if (!m) continue
    const key = m[1]
    const val = m[2].trim()
    // Start of multi-line array
    if (val === '') {
      pendingKey = key
      arrayItems = []
      continue
    }
    fields.push([key, val.replace(/^["']|["']$/g, '')])
    pendingKey = ''
  }
  if (pendingKey && arrayItems.length > 0) {
    fields.push([pendingKey, `[${arrayItems.join(', ')}]`])
  }

  return { fields, body }
}

function getField(fields: string[][], key: string): string {
  const lower = key.toLowerCase()
  return fields.find(([k]) => k.toLowerCase() === lower)?.[1] ?? ''
}

function normaliseDate(raw: string): string {
  const s = raw.trim().replace(/^["'\[\]]+|["'\[\]]+$/g, '')
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s
  const dtMatch = s.match(/^(\d{4}-\d{2}-\d{2})[T \d:+Z-]/)
  if (dtMatch) return dtMatch[1]
  const wikiMatch = s.match(/\[\[(\d{4}-\d{2}-\d{2})/)
  if (wikiMatch) return wikiMatch[1]
  const parsed = Date.parse(s)
  if (!isNaN(parsed)) return new Date(parsed).toISOString().slice(0, 10)
  return s
}

function normaliseTags(raw: string): string {
  if (!raw || raw === '[]') return '[]'
  const content = raw.replace(/^\[|\]$/g, '')
  const tags = content.split(',')
    .map(t => t.trim().replace(/^["'#]+|["']+$/g, '').trim())
    .filter(Boolean)
  return tags.length ? `[${tags.join(', ')}]` : '[]'
}

function serialise(fields: string[][]): string {
  const ORDER = ['title', 'type', 'date', 'tags', 'source', 'status', 'topic', 'url',
    'attendees', 'company', 'summary']
  const seen = new Set<string>()
  const lines: string[] = []

  const add = (k: string, v: string) => { lines.push(`${k}: ${v}`); seen.add(k.toLowerCase()) }

  for (const key of ORDER) {
    const pair = fields.find(([k]) => k.toLowerCase() === key)
    if (pair) add(pair[0], pair[1])
  }
  for (const [k, v] of fields) {
    if (!seen.has(k.toLowerCase())) add(k, v)
  }
  return lines.join('\n')
}

async function processFile(filePath: string) {
  const relPath = relative(VAULT, filePath)
  if (isExcluded(filePath)) { counters.skipped++; return }

  let content: string
  try { content = await Bun.file(filePath).text() }
  catch (e) { log(`[ERROR] ${relPath}: read failed — ${e}`); counters.errors++; return }

  const parsed = extractFrontmatter(content)

  // No frontmatter — inject minimal
  if (!parsed) {
    const title = filePath.split('/').pop()?.replace(/\.md$/i, '') || 'Untitled'
    const s = await stat(filePath).catch(() => null)
    const d = s ? new Date(s.mtimeMs).toISOString().slice(0, 10) : new Date().toISOString().slice(0, 10)
    const newContent = `---\ntitle: ${title}\ntype: note\ndate: ${d}\ntags: []\nsource: \n---\n${content}`
    log(`[MODIFIED] ${relPath} — injected missing frontmatter`)
    counters.modified++
    if (!DRY_RUN) await Bun.write(filePath, newContent)
    return
  }

  const { fields, body } = parsed
  const changes: string[] = []
  let outFields = [...fields]

  const getF = (k: string) => getField(outFields, k)
  const setF = (key: string, val: string) => {
    const idx = outFields.findIndex(([k]) => k.toLowerCase() === key.toLowerCase())
    if (idx !== -1) outFields[idx] = [outFields[idx][0], val]
    else outFields.push([key, val])
  }
  const delF = (key: string) => { outFields = outFields.filter(([k]) => k.toLowerCase() !== key.toLowerCase()) }

  // Skip pai-session
  if (getF('type') === 'pai-session') { log(`[SKIPPED] ${relPath} — pai-session`); counters.skipped++; return }

  // Type filter
  if (TYPE_FILTER && getF('type') !== TYPE_FILTER) { counters.skipped++; return }

  // 1. Date
  const dc = getF('date-created') || getF('date_created')
  const da = getF('date-added') || getF('date_added')
  const existingDate = getF('date')
  let targetDate = existingDate

  if (dc) {
    targetDate = normaliseDate(dc)
    delF('date-created'); delF('date_created')
  } else if (da) {
    targetDate = normaliseDate(da)
    delF('date-added'); delF('date_added')
  } else if (existingDate) {
    targetDate = normaliseDate(existingDate)
  } else {
    const s = await stat(filePath).catch(() => null)
    targetDate = s ? new Date(s.mtimeMs).toISOString().slice(0, 10) : new Date().toISOString().slice(0, 10)
  }
  if (targetDate !== existingDate) {
    changes.push(`date: "${existingDate || '(missing)'}" → "${targetDate}"`)
    setF('date', targetDate)
  }

  // 2. Tags
  const existingTags = getF('tags')
  const normTags = normaliseTags(existingTags)
  if (normTags !== existingTags) {
    changes.push(`tags: ${existingTags || '(missing)'} → ${normTags}`)
    setF('tags', normTags)
  }
  if (!existingTags) {
    setF('tags', '[]')
    changes.push('tags: (missing) → []')
  }

  // 3. Type — note both capitalisations via getF case-insensitive
  const currentType = getF('type')
  if (!currentType) {
    setF('type', 'note')
    changes.push('type: (missing) → note')
  } else if (currentType === 'voice') {
    setF('type', 'capture')
    setF('source', 'voice')
    changes.push('type: voice → capture')
    changes.push('source: added → voice')
  }

  // 4. Title
  if (!getF('title')) {
    const derived = filePath.split('/').pop()?.replace(/\.md$/i, '').replace(/^\d{4}-\d{2}-\d{2}\s+/, '') || 'Untitled'
    setF('title', derived)
    changes.push(`title: (missing) → ${derived}`)
  }

  // 5. Source (add empty if missing for capture/note)
  const finalType = getF('type')
  if (!getF('source') && (finalType === 'capture' || finalType === 'note')) {
    setF('source', '')
    changes.push('source: (added empty)')
  }

  if (changes.length === 0) { counters.unchanged++; return }

  const newFm = serialise(outFields)
  const newContent = `---\n${newFm}\n---${body}`

  log(`[MODIFIED] ${relPath}`)
  changes.forEach(c => log(`  ${c}`))
  counters.modified++

  if (!DRY_RUN) {
    try { await Bun.write(filePath, newContent) }
    catch (e) { log(`[ERROR] ${relPath}: write failed — ${e}`); counters.errors++; counters.modified-- }
  }
}

async function walkDir(dir: string) {
  let entries: string[]
  try { entries = await readdir(dir) } catch { return }
  for (const e of entries) {
    const full = join(dir, e)
    let s
    try { s = await stat(full) } catch { continue }
    if (s.isDirectory()) await walkDir(full)
    else if (e.endsWith('.md')) await processFile(full)
  }
}

async function main() {
  const mode = DRY_RUN ? 'DRY RUN' : 'LIVE'
  log(`=== MigrateVaultFrontmatter — ${mode} ===`)
  if (FOLDER_FILTER) log(`Folder filter: "${FOLDER_FILTER}"`)
  if (TYPE_FILTER) log(`Type filter: "${TYPE_FILTER}"`)

  const folders = FOLDER_FILTER ? [FOLDER_FILTER] : ACTIVE_FOLDERS
  for (const folder of folders) {
    log(`--- ${folder} ---`)
    await walkDir(join(VAULT, folder))
  }

  log(`\n=== SUMMARY (${mode}) ===`)
  log(`Modified:  ${counters.modified}`)
  log(`Skipped:   ${counters.skipped}`)
  log(`Unchanged: ${counters.unchanged}`)
  log(`Errors:    ${counters.errors}`)

  await Bun.write(LOG_PATH, logLines.join('\n') + '\n').catch(() => {})
}

main().catch(console.error)

