VAULT="/opt/docker/appdata/obsidian-jellybase/vault/OB_v2"
QA="$VAULT/.obsidian/plugins/quickadd/data.json"
# ISC-1: exactly 3 choices
echo "ISC-1 (3 choices):" $(python3 -c "import json; d=json.load(open('$QA')); print('PASS' if len(d['choices'])==3 else 'FAIL')")
# ISC-2: Capture choice name + templatePath
echo "ISC-2 (Capture name+path):" $(python3 -c "import json; d=json.load(open('$QA')); c=d['choices'][0]; print('PASS' if c['name']=='📥 Capture' and 'Capture Template' in c['templatePath'] else 'FAIL:'+str(c))")
# ISC-3: Meeting
echo "ISC-3 (Meeting name+path):" $(python3 -c "import json; d=json.load(open('$QA')); c=d['choices'][1]; print('PASS' if c['name']=='🗣️ Meeting' and 'Meeting Template' in c['templatePath'] else 'FAIL:'+str(c))")
# ISC-4: Note
echo "ISC-4 (Note name+path):" $(python3 -c "import json; d=json.load(open('$QA')); c=d['choices'][2]; print('PASS' if c['name']=='💡 Note' and 'Note Template' in c['templatePath'] else 'FAIL:'+str(c))")
# ISC-5: Capture → 00 INBOX
echo "ISC-5 (Capture→00 INBOX):" $(python3 -c "import json; d=json.load(open('$QA')); print('PASS' if '00 INBOX' in d['choices'][0]['folder']['folders'] else 'FAIL')")
# ISC-6: Meeting → 02 Cards/Meetings
echo "ISC-6 (Meeting→02 Cards/Meetings):" $(python3 -c "import json; d=json.load(open('$QA')); print('PASS' if '02 Cards/Meetings' in d['choices'][1]['folder']['folders'] else 'FAIL')")
# ISC-7: Note → 02 Cards
echo "ISC-7 (Note→02 Cards):" $(python3 -c "import json; d=json.load(open('$QA')); print('PASS' if '02 Cards' in d['choices'][2]['folder']['folders'] else 'FAIL')")
# ISC-8: all openFile: true
echo "ISC-8 (openFile true):" $(python3 -c "import json; d=json.load(open('$QA')); print('PASS' if all(c.get('openFile') for c in d['choices']) else 'FAIL')")
# ISC-9: no old names
echo "ISC-9 (no old names):" $(python3 -c "import json; d=json.load(open('$QA')); names=[c['name'] for c in d['choices']]; bad=['New Tool','New Idea','New Concept','New Learning Note','Test Modal']; print('PASS' if not any(b in names for b in bad) else 'FAIL')")
# ISC-10: no Multi type
echo "ISC-10 (no Multi):" $(python3 -c "import json; d=json.load(open('$QA')); print('PASS' if not any(c.get('type')=='Multi' for c in d['choices']) else 'FAIL')")

